def test_tc_ecm_eng_001(can_bus):
    start = time.time()
    count = 0
    while time.time() - start < 10:
        m = can_bus.recv(0.5)
        if m and m.arbitration_id == MSG_ID_ECM:
            count += 1
    assert count >= 8

def test_tc_ecm_eng_002(can_bus):
    msg = can_bus.recv(timeout=1.0)
    assert get_raw_temp(msg) == 40

def test_tc_ecm_eng_005(can_bus):
    msg = can_bus.recv(timeout=1.0)
    assert get_raw_temp(msg) == 130

def test_tc_ecm_eng_006(can_bus):
    vals = [get_phys_temp(can_bus.recv()) for _ in range(5)]
    assert vals == sorted(vals)

def test_tc_ecm_eng_007(can_bus):
    start = time.time()
    msgs = []
    while time.time() - start < 20:
        m = can_bus.recv(0.1)
        if m and m.arbitration_id == MSG_ID_ECM:
            msgs.append(m)
    assert len(msgs) >= 16

def test_tc_ecm_eng_008(can_bus):
    msg = can_bus.recv(timeout=1.0)
    assert get_phys_temp(msg) <= 215

def test_tc_ecm_eng_010(can_bus):
    msg = can_bus.recv(timeout=1.0)
    assert msg.arbitration_id == 0x208
